INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (9862, '10088168', 'YachtWorld', 'https://www.yachtworld.com/yacht/1999-azimut-85-ultimate-10088168/', 'Azimut', '85 Ultimate', 1999, '85ft', '895000', 'USD', 'Stuart, Florida', 'Stuart', 'Florida', 'US', '1999 85’ Azimut Ultimate - No disappointments with this vessel, the nicest 85'' Azimut on the market. Although the 1999 85’ Azimut Ultimate will not be exhibited at the West Palm Beach Boat Show, she is conveniently located just 45 minutes from the show venue. Private courtesy showings will be arranged during show week for qualified buyers by advance appointment. For those attending the show and seeking a serious 85-foot motor yacht opportunity without competing dock traffic, this presents an ideal private viewing option. Refit & Upgrades • New Garmin radar system • New Garmin autopilot • Fully networked electronics between wheelhouse and flybridge helm • New joystick steering system • New AIS tracking system • Two new life rafts (8’ and 6’) • Fire system re-certified (September 8, 2025) • New bottom paint (September 2025) • Running gear painted with Prop Speed (September 2025) • New 8’ antenna for VHF and AIS • New 50” smart TVs – Master, VIP, and aft deck • New 40” TVs – guest cabins and wheelhouse • Eight new security cameras • New alarm system • Oil service completed (September 2025) • New batteries (2026) • Generators rebuilt (late 2025) • Watermaker rebuilt (2024) • Insurance survey & refit completed (August 27, 2025) • New refrigerator (2025) • New dishwasher (2025) • Garmin navigation suite (2025), networked at main helm and flybridge including:– GPS– Dual VHF radios– Chartplotter– Depth sounder– Compass– Log-speedometer • New hot water heater (2025) Some yachts look impressive at the dock.Others tell a story the moment you step aboard. This 85’ Azimut Ultimate does both. From her unmistakable Italian lines to the warmth of her high-gloss cherry interior, she delivers the scale, layout, and presence that made Azimut’s 85 Ultimate one of the most admired yachts of…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/93/58/1999-azimut-85-ultimate-power-9989358-20251222103903726-1.jpg?w=1920&h=267&t=1771859746000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/19/7900619_20220526101004731_1_XLARGE.jpg?w=1920&ratio=default&t=1771859746000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/19/7900619_20220526101023837_1_XLARGE.jpg?w=1920&ratio=default&t=1771859746000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/19/7900619_20220526102324855_1_XLARGE.jpg?w=1920&ratio=default&t=1771859746000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/19/7900619_20210528131312855_1_XLARGE.jpg?w=1920&ratio=default&t=1771859746000&exact=&format=webp","https://images.boatsgr