INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (22534, '10053341', 'YachtWorld', 'https://www.yachtworld.com/yacht/2020-jeanneau-nc-1095-10053341/', 'Jeanneau', 'NC 1095', 2020, '34ft', '275000', 'USD', 'St Petersburg, Florida', 'St Petersburg', 'Florida', 'US', 'This 2020 NC 1095 stands out as one of the most practical and value-packed family cruisers in its class. Owners and reviewers consistently praise it for delivering exceptional space, versatility, and affordability in a manageable 34-foot outboard-powered package. Some of it''s key features are: Modular cockpit with easy side access Recessed side-deck on starboard Bright salon with sliding doors, skylights, and panoramic windows Optimized storage spaces throughout for extended trips True 3-cabin layout (rare in this size range) Generator + air conditioning for full comfort underway or at anchor Sliding side door at the helm for effortless single handed docking Twin Yamaha 300hp outboard powered cruiser Bow Thruster for stress free docking Incredibly flat acceleration and ride Trailer available.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260201092920182-2.jpg?w=1920&h=267&t=1769967861000&exact=&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170240994-2.jpg?w=1920&ratio=default&t=1772145294000&exact=&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170241147-3.jpg?w=1920&ratio=default&t=1772145294000&exact=&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170241927-1.jpg?w=1920&ratio=default&t=1772145294000&exact=&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170242096-2.jpg?w=1920&ratio=default&t=1772145294000&exact=&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170242316-3.jpg?w=1920&ratio=default&t=1772145294000&exact=&format=webp"]', 'Boat DetailsDescriptionThis 2020 NC 1095 stands out as one of the most practical and value-packed family cruisers in its class. Owners and reviewers consistently praise it for delivering exceptional space, versatility, and affordability in a manageable 34-foot outboard-powered package. Some of it''s key features are: Modular cockpit with easy side access Recessed side-deck on starboard Bright salon with sliding doors, skylights, and panoramic windows Optimized storage spaces throughout for extended trips True 3-cabin layout (rare in this size range) Generator + air conditioning for full comfort underway or at anchor Sliding side door at the helm for effortless single handed docking Twin Yamaha 300hp outboard powered cruiser Bow Thruster for stress free docking Incredibly flat acceleration and ride Trailer available.Show MoreContact InformationPlease contact Alan Levitz at 727-527-2800Other DetailsHelmErgonomic & Comfortable Helm The helm aboard this NC 1095 is thoughtfully designed for both comfort and total control. A supportive helm seat faces a clean, well-organized dash with everything exactly where you want it. Front and center is the Garmin navigation display, complemented by the Fusion stereo interface and Yamaha digital engine management system for at-a-glance monitoring. The adjustable steering wheel is flanked by intuitive controls—throttles to starboard, with bow thruster, trim, and switching systems conveniently positioned to port. A sliding side door at the helm provides immediate access to the side deck, making single-handed docking and line handling simple, safe, and efficient.SalonBright Salon & Functional Galley The salon is filled with natural light, offering panoramic views that create an open, inviting atmosphere rarely found in this size range. Desig…', '2026-04-01T18:18:07.423Z', '2026-04-01T18:18:07.423Z', NULL, NULL, NULL, NULL, 'Please contact Alan Levitz at 727-527-2800', 'Alan Levitz', '727-527-2800', 'HelmErgonomic & Comfortable Helm The helm aboard this NC 1095 is thoughtfully designed for both comfort and total control. A supportive helm seat faces a clean, well-organized dash with everything exactly where you want it. Front and center is the Garmin navigation display, complemented by the Fusion stereo interface and Yamaha digital engine management system for at-a-glance monitoring. The adjustable steering wheel is flanked by intuitive controls—throttles to starboard, with bow thruster, trim, and switching systems conveniently positioned to port. A sliding side door at the helm provides immediate access to the side deck, making single-handed docking and line handling simple, safe, and efficient.SalonBright Salon & Functional Galley The salon is filled with natural light, offering panoramic views that create an open, inviting atmosphere rarely found in this size range. Designed for both comfort and practicality, this space is ideal for weekend getaways, coastal cruising, or extended adventures like the Great Loop or Bahamas crossings. The layout maximizes usable living space without ever feeling confined. Large hull windows, opening side windows, and expansive sunroofs bring th…', 'Preferred Yachts offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice. Co-Brokerage Agreement Preferred Yachts offers this listing on a 50-50 split with PY approved corresponding Florida licensed yacht brokerages. Brokers unlicensed in Florida must contact listing broker to make arrangements that comply with Florida law.', 'Electrical EquipmentShore Power Inlet:✓Generator:✓ElectronicsDepthsounder:✓Plotter:✓Autopilot:✓Radio:✓GPS:✓Cockpit Speakers:✓VHF:✓AIS:✓Inside EquipmentBow Thruster:✓Electric Bilge Pump:✓Microwave Oven:✓Air Conditioning:✓Electric Head:✓Hot Water:✓Refrigerator:✓Battery Charger:✓Outside EquipmentCockpit Shower:✓Electric Winch:✓Cockpit Cushions:✓Cockpit Table:✓Swimming Ladder:✓', 'Shore Power Inlet | Generator', 'Depthsounder | Plotter | Autopilot | Radio | GPS | Cockpit Speakers | VHF | AIS', 'Bow Thruster | Electric Bilge Pump | Microwave Oven | Air Conditioning | Electric Head | Hot Water | Refrigerator | Battery Charger', 'Cockpit Shower | Electric Winch | Cockpit Cushions | Cockpit Table | Swimming Ladder', NULL, 'Engine 1Engine Make:YamahaTotal Power:300hpEngine Hours:412Engine Type:OutboardEngine 2Engine Make:YamahaTotal Power:300hpEngine Hours:412Engine Type:Outboard', 'Yamaha', NULL, NULL, '300hp', '412', 'Outboard', NULL, NULL, NULL, NULL, 'DimensionsLength Overall:34.42ftMin Draft:2.33ftBeam:11.08ftWeightsDry Weight:10,225LbMiscellaneousDeadrise At Transom:16degHull Material:FiberglassHull Shape:Modified VeeTanksFresh Water Tank:68 gal Fuel Tank:2 x 106 gal Holding Tank:AccommodationsGuest Cabins:3Guest Heads:1', NULL, NULL, NULL, '34.42ft', NULL, NULL, '2.33ft', '11.08ft', '10,225Lb', NULL, NULL, '16deg', 'Fiberglass', 'Modified Vee', NULL, '68 gal', '2 x 106 gal', NULL, '1', '["https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260201092920182-2.jpg?w=1028&ratio=default&t=1769967861000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170240994-2.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170241147-3.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170241927-1.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170242096-2.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170242316-3.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170242466-4.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp","https://images.boatsgroup.com/resize/1/33/41/2020-jeanneau-nc-1095-power-10053341-20260111170243000-1.jpg?w=1028&ratio=default&t=1772145294000&exact&format=webp"]', NULL, NULL, NULL, NULL, 'St Petersburg, Florida, US', 'St Petersburg', 'Florida', 'US', NULL, NULL, 'city', 'apple', 'failed', 'St Petersburg, Florida, US', 'no_strong_match', '2026-04-01T18:18:07.423Z', 1, 0);
