INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (14986, '9996647', 'YachtWorld', 'https://www.yachtworld.com/yacht/2026-grady--white-251-coastal-explorer-9996647/', 'Grady-White', '251 Coastal Explorer', 2026, '25ft', '116425', 'USD', 'Seabrook, Texas', 'Seabrook', 'Texas', 'US', 'Just landed and ready to make waves! The 251 Coastal Explorer is aptly named. Built on Grady''s SeaV2 hull, the 251 offers more offshore capability and performance than any other inshore fishing boat. With built-in rod storage, bow and stern fishing platforms , and a deluxe lean bar with lockable storage and a 25-gallon livewell, this 25-foot center console boat is packed with fishing features. Its numerous family -friendly amenities including a head area, plenty of water sport storage, and low gunnels for easy access to the water makes it the best fishing and family center console boat. Key Features Experience Luxury - Embark on thrilling adventures aboard this top-of-the-line Grady-White model, promising superior performance and unmatched craftsmanship for the ultimate boating experience. Unleash Power and Precision - Equipped with a standard Yamaha four-stroke engine generating 300 horsepower, this vessel ensures a smooth and powerful ride with precise handling on the water. Crafted for Luxury and Comfort - Step aboard and indulge in the plush amenities and elegant design that elevate your time spent at sea, offering relaxation and luxury at every turn. Performance - With a top end speed of 49.6 miles per hour at 5,800 RPM and a cruising speed of 27.1 miles per hour 3,300 RPM the Yamaha four-stroke 300 horsepower outboard engine will get up and get you to where you are trying to go with ease. Whether that is fishing in shallow waters or spending the day out cruising under the sun, the power and performance on this 251 Coastal Explorer will take you there.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403710-0.jpg?w=1920&h=267&t=1774879654000&exact=&format=webp","https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403719-1.jpg?w=1920&ratio=default&t=1774879653000&exact=&format=webp","https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403727-2.jpg?w=1920&ratio=default&t=1774879654000&exact=&format=webp","https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403735-3.jpg?w=1920&ratio=default&t=1774879654000&exact=&format=webp","https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403742-4.jpg?w=1920&ratio=default&t=1774879653000&exact=&format=webp","https://images.boatsgroup.com/resize/1/66/47/2026-grady-white-251-coastal-explorer-power-9996647-20251030100403751-5.jpg?w=1920&ratio=default&t=1774879653000&exact=&format=webp"]', 'Boat DetailsDescription Just landed and ready to make waves! The 251 Coastal Explorer is aptly named. Built on Grady''s SeaV2 hull, the 251 offers more offshore capability and performance than any other inshore fishing boat. With built-in rod storage, bow and stern fishing platforms , and a deluxe lean bar with lockable storage and a 25-gallon livewell, this 25-foot center console boat is packed with fishing features. Its numerous family -friendly amenities including a head area, plenty of water sport storage, and low gunnels for easy access to the water makes it the best fishing and family center console boat. Key Features Experience Luxury - Embark on thrilling adventures aboard this top-of-the-line Grady-White model, promising superior performance and unmatched craftsmanship for the ultimate boating experience. Unleash Power and Precision - Equipped with a standard Yamaha four-stroke engine generating 300 horsepower, this vessel ensures a smooth and powerful ride with precise handling on the water. Crafted for Luxury and Comfort - Step aboard and indulge in the plush amenities and elegant design that elevate your time spent at sea, offering relaxation and luxury at every turn. Performance - With a top end speed of 49.6 miles per hour at 5,800 RPM and a cruising speed of 27.1 miles per hour 3,300 RPM the Yamaha four-stroke 300 horsepower outboard engine will get up and get you to where you are trying to go with ease. Whether that is fishing in shallow waters or spending the day out cruising under the sun, the power and performance on this 251 Coastal Explorer will take you there. Show MorePropulsionEngine Make:YAMAHAEngine Model:WHT F300 IDESTotal Power:300hpEngine Type:OutboardDrive Type:OtherFuel Type:GasSpecificationsDimensionsLength Overall:24ftMax Draft:1.33ftBeam…', '2026-04-01T18:11:46.999Z', '2026-04-01T18:11:46.999Z', NUL