INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (22354, '10078021', 'YachtWorld', 'https://www.yachtworld.com/yacht/2009-sea-ray-47-sedan-bridge-10078021/', 'Sea', 'Ray 47 Sedan Bridge', 2009, '51ft', '389000', 'USD', 'Pottsboro, Texas', 'Pottsboro', 'Texas', 'US', 'Professionally maintained 2009 Sea Ray 47 Sedan Bridge with ~500hrs on Cummins QSC 8.3L diesel engines This 2009 Sea Ray 47 Sedan Bridge is a standout example of one of Sea Ray’s most popular and versatile cruising yachts. Professionally maintained and thoughtfully cared for, this vessel is powered by twin Cummins QSC 8.3L diesel engines with ~500 hours, delivering excellent performance, reliability, and efficiency. Designed for comfortable cruising and entertaining, the 47 Sedan Bridge features an expansive flybridge with excellent visibility, generous seating, and a wet bar — ideal for extended days on the water. The cockpit offers easy access to the swim platform and ample space for dockside or on-the-hook entertaining. Inside, the salon is bright and open with large windows, high-quality finishes, and comfortable seating throughout. The two-stateroom, two-head layout provides privacy and comfort for owners and guests alike. A fully equipped galley includes ample storage, solid-surface countertops, and modern appliances suitable for extended cruising. This boat has been professionally serviced, with systems maintained to a high standard. The low engine hours for her age reflect careful ownership and consistent upkeep. She presents as a strong candidate for buyers seeking a turn-key Sedan Bridge with proven Cummins power. Highlights Include: Twin Cummins QSC 8.3 diesel engines (~500hrs) Onan Generator (~2000hrs) Professionally maintained with service history Spacious flybridge with seating and wet bar Open and bright salon with premium finishes Two stateroom / two head layout Well-appointed galley for cruising comfort Excellent Sea Ray build quality and design The Sea Ray 47 Sedan Bridge remains one of the most desirable yachts in her class due to her balance of perfo…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/80/21/2009-sea-ray-47-sedan-bridge-power-10078021-20260212125829702-1.jpg?w=1920&h=267&t=1770930873000&exact=&format=webp","https://images.boatsgroup.com/resize/1/80/21/2009-sea-ray-47-sedan-bridge-power-10078021-20260212125829946-2.jpg?w=1920&ratio=default&t=1770930868000&exact=&format=webp","https://images.boatsgroup.com/resize/1/80/21/2009-sea-ray-47-sedan-bridge-power-10078021-20260212125830274-3.jpg?w=1920&ratio=default&t=1770930880000&exact=&format=webp","https://images.boatsgroup.com/resize/1/80/21/2009-sea-ray-47-sedan-bridge-power-10078021-20260212125831814-1.jpg?w=1920&ratio=default&t=1770930831000&exact=&format=webp","https://images.boatsgroup.com/resize/1/80/21/2009-sea-r