INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (16518, '10131888', 'YachtWorld', 'https://www.yachtworld.com/yacht/1999-viking-58-convertible-10131888/', 'Viking', '58 Convertible', 1999, '59ft', '750000', 'USD', 'Freeport, Texas', 'Freeport', 'Texas', 'US', 'Stunning 58 Viking Golan was originally commissioned new as Ships Café for a highly knowledgeable original owner and represents a rare blend of Viking engineering and Merritt Boatworks craftsmanship. Upon delivery from Viking, the vessel was taken directly to Merritt Boatworks, where she underwent an additional seven months of extensive customization, resulting in a truly one‑of‑a‑kind yacht that combines proven offshore performance with refined custom aesthetics. The Merritt refit included the addition of a full custom tower, mezzanine seating area, teak cockpit decking, teak covering boards, and a high‑gloss teak rub rail. Lifting rails were added to the hull, significantly improving ride quality, handling, and efficiency offshore. Inside, the salon received custom Merritt windows, a custom galley, and a custom dining table, along with numerous additional refinements that elevate both comfort and finish. The result is a vessel that truly offers the best of both worlds—Viking’s proven hull design and mechanical reliability, paired with Merritt’s legendary fit, finish, and custom detailing. Performance, Range & Layout Golan is equipped with three aluminum fuel tanks totaling approximately 1,800+ gallons, providing an impressive range exceeding 1,000 nautical miles at economical cruise, making her well suited for extended offshore use. The layout features three staterooms and three heads, offering excellent comfort and privacy for owners and guests on long trips. Ownership, Use & Condition Golan has benefited from ownership by knowledgeable yachtsmen and a consistent, well‑documented maintenance program. The vessel was professionally painted in 2015 and has since received annual haul‑outs and regular waxing, keeping the hull and topsides in excellent condition. The most…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154129147-2.jpg?w=400&h=267&t=1774887313000&exact&format=webp","https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154130332-4.jpg?w=200&ratio=default&t=1774887313000&exact&format=webp","https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154126116-3.jpg?w=200&ratio=default&t=1774887313000&exact&format=webp","https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154121335-1.jpg?w=200&ratio=default&t=1774887313000&exact&format=webp","https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154128576-1.jpg?w=200&ratio=default&t=1774887313000&exact&format=webp","https://images.boatsgroup.com/resize/1/18/88/1999-viking-58-convertible-power-10131888-20260329154118828-3.jpg?w=200&ratio=default&t=1774887313000&exact&format=webp"]', 'Boat DetailsDescriptionStunning 58 Viking Golan was originally commissioned new as Ships Café for a highly knowledgeable original owner and represents a rare blend of Viking engineering and Merritt Boatworks craftsmanship. Upon delivery from Viking, the vessel was taken directly to Merritt Boatworks, where she underwent an additional seven months of extensive customization, resulting in a truly one‑of‑a‑kind yacht that combines proven offshore performance with refined custom aesthetics. The Merritt refit included the addition of a full custom tower, mezzanine seating area, teak cockpit decking, teak covering boards, and a high‑gloss teak rub rail. Lifting rails were added to the hull, significantly improving ride quality, handling, and efficiency offshore. Inside, the salon received custom Merritt windows, a custom galley, and a custom dining table, along with numerous additional refinements that elevate both comfort and finish. The result is a vessel that truly offers the best of both worlds—Viking’s proven hull design and mechanical reliability, paired with Merritt’s legendary fit, finish, and custom detailing. Performance, Range & Layout Golan is equipped with three aluminum fuel tanks totaling approximately 1,800+ gallons, providing an impressive range exceeding 1,000 nautical miles at economical cruise, making her well suited for extended offshore use. The layout features three staterooms and three heads, offering excellent comfort and privacy for owners and guests on long trips. Ownership, Use & Condition Golan has benefited from ownership by knowledgeable yachtsmen and a consistent, well‑documented maintenance program. The vessel was professionally painted in 2015 and has since received annual haul‑outs and regular waxing, keeping the hull and topsides in excelle…', '2026-03-31T21:01:06.754Z', '2026-03-31T21:01:06.754Z', NULL, NULL, NULL, NULL, 'Please contact Elan Shney at 8322696055', 'Elan Shney', '8322696055', 'DisclaimerThe Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', 'The Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', 'Electrical EquipmentShore Power Inlet:✓Generator:✓Inverter:✓ElectronicsDepthsounder:✓Radar:✓Log-Speedometer:✓Radar Detector:✓Wind Speed and Direction:✓Computer:✓Repeater(s):✓TV Set:✓Navigation Center:✓Plotter:✓DVD Player:✓Autopilot:✓Radio:✓Compass:✓CD Player:✓GPS:✓Cockpit Speakers:✓VHF:✓Flat Screen TV:✓Wi-Fi:✓AIS:✓Inside EquipmentBow Thruster:✓Washing Machine:✓Electric Bilge Pump:✓Oven:✓Manual Bilge Pump:✓Microwave Oven:✓Marine Head:✓Air Conditioning:✓Heating:✓Hot Water:✓Refrigerator:✓Fresh Water Maker:✓Deep Freezer:✓Sea Water Pump:✓Battery Charger:✓Outside EquipmentTeak Cockpit:✓Electric Winch:✓Teak Sidedecks:✓Davit(s):✓Radar Reflector:✓Tender:✓Cockpit Cushions:✓Cockpit Table:✓Fin Stabilizer:✓Outriggers:✓', 'Shore Power Inlet | Generator | Inverter', 'Depthsounder | Radar | Log-Speedometer | Radar Detector | Wind Speed and Direction | Computer | Repeater(s) | TV Set | Navigation Center | Plotter | DVD Player | Autopilot | Radio | Compass | CD Player | GPS | Cockpit Speakers | VHF | Flat Screen TV | Wi-Fi | AIS', 