INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (22546, '9941143', 'YachtWorld', 'https://www.yachtworld.com/yacht/2005-mainship-pilot-34-sedan-9941143/', 'Mainship', 'Pilot 34 Sedan', 2005, '34ft', '198500', 'USD', 'Oxnard, California', 'Oxnard', 'California', 'US', '"Third Day" has recently undergone a comprehensive upgrade, featuring new electronics, a FLIR camera, Satellite TV, synthetic teak flooring at the helm, new canvas, an aluminum floor dinghy, and more. This is a fully equipped and well-maintained example of the top-of-the-line Mainship 34, featuring the full RumRunner II option package. Twin Yanmar diesels with low hours, a 5 kW generator with reverse-cycle heat and air, newer canvas, and a custom forward berth mattress set set "Third Day" apart from the standard Mainship 34.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121534440-1.jpg?w=1920&ratio=default&t=1758655890000&exact=&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121622865-3.jpg?w=1920&ratio=default&t=1758655958000&exact=&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121535054-2.jpg?w=1920&ratio=default&t=1758655894000&exact=&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121535722-3.jpg?w=1920&ratio=default&t=1758655844000&exact=&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121536280-4.jpg?w=1920&ratio=default&t=1758655918000&exact=&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121538657-1.jpg?w=1920&ratio=default&t=1758655866000&exact=&format=webp"]', 'Boat DetailsDescription"Third Day" has recently undergone a comprehensive upgrade, featuring new electronics, a FLIR camera, Satellite TV, synthetic teak flooring at the helm, new canvas, an aluminum floor dinghy, and more. This is a fully equipped and well-maintained example of the top-of-the-line Mainship 34, featuring the full RumRunner II option package. Twin Yanmar diesels with low hours, a 5 kW generator with reverse-cycle heat and air, newer canvas, and a custom forward berth mattress set set "Third Day" apart from the standard Mainship 34. Contact InformationPlease contact Bob Nahm at 805.666.9676Other DetailsManufacturer Provided Description The Mainship Pilot 34 has the seakeeping abilities of the lobster boats it has descended from. It has a steep plumb bow and a gentle rise of the sheer; both of these qualities give the Pilot 34 the ability to cut through head seas, while the rounded forward hull sections provide a soft entry. Flatter sections aft increase lift for speed and economy, and the deep full keel with a complete sand shoe gives stability and protection from grounding. In the cockpit, the Pilot 34 features double-wide helm and companion seats flanking the large, hydraulically assisted engine access hatch. The side lounges can double as berths with the removable backrests. A tilt-up console provides easy access to electronics and wiring, and it features a built-in insulated cooler box, as well as a standard transom door. Below, the cabin features a spacious head, complete with a Corian-covered vanity, ample storage, a shower, and even a VacuFlush toilet. The teak-trimmed galley offers ample storage, a generous Corian counter space, a microwave, a dual cooktop, and a refrigerator and freezer. There is even a slide-out pantry for convenience. The large…', '2026-04-01T18:18:41.625Z', '2026-04-01T18:18:41.625Z', NULL, NULL, NULL, NULL, 'Please contact Bob Nahm at 805.666.9676', 'Bob Nahm', '805.666.9676', 'Manufacturer Provided Description The Mainship Pilot 34 has the seakeeping abilities of the lobster boats it has descended from. It has a steep plumb bow and a gentle rise of the sheer; both of these qualities give the Pilot 34 the ability to cut through head seas, while the rounded forward hull sections provide a soft entry. Flatter sections aft increase lift for speed and economy, and the deep full keel with a complete sand shoe gives stability and protection from grounding. In the cockpit, the Pilot 34 features double-wide helm and companion seats flanking the large, hydraulically assisted engine access hatch. The side lounges can double as berths with the removable backrests. A tilt-up console provides easy access to electronics and wiring, and it features a built-in insulated cooler box, as well as a standard transom door. Below, the cabin features a spacious head, complete with a Corian-covered vanity, ample storage, a shower, and even a VacuFlush toilet. The teak-trimmed galley offers ample storage, a generous Corian counter space, a microwave, a dual cooktop, and a refrigerator and freezer. There is even a slide-out pantry for convenience. The large dinette easily converts…', 'The Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice. Owner''s personal items excluded. Exclusions include, however are not limited to, Seller''s personal possessions, loose items, binoculars, handheld radio(s), charts, tools, fishing equipment, spare parts, clothing and foul weather gear, galley equipment, linens/bedding and any items not specifically listed on equipment list', NULL, NULL, NULL, NULL, NULL, NULL, 'Engine 1Engine Make:YanmarEngine Model:4LHA-STPEngine Year:2005Total Power:240hpEngine Hours:722Engine Type:InboardDrive Type:Direct DriveFuel Type:DieselEngine 2Engine Make:YanmarEngine Model:4LHA-STPEngine Year:2005Total Power:240hpEngine Hours:723Engine Type:InboardDrive Type:Direct DriveFuel Type:Diesel', 'Yanmar', '4LHA-STP', '2005', '240hp', '722 | 723', 'Inboard', 'Direct Drive', 'Diesel', NULL, NULL, 'DimensionsLength Overall:34ftBeam:12.25ftMiscellaneousHull Material:FiberglassTanksFresh Water Tank:70 gal Fuel Tank:250 gal Holding Tank:20 gal AccommodationsGuest Heads:1', NULL, NULL, NULL, '34ft', NULL, NULL, NULL, '12.25ft', NULL, NULL, NULL, NULL, 'Fiberglass', NULL, NULL, '70 gal', '250 gal', '20 gal', '1', '["https://images.boatsgroup.com/resize/1/55/18/7295518_20191127110743252_1_XLARGE.jpg?w=1028&ratio=default&t=1757518212000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121534440-1.jpg?w=1028&ratio=default&t=1758655890000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121622865-3.jpg?w=1028&ratio=default&t=1758655958000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121535054-2.jpg?w=1028&ratio=default&t=1758655894000&exact&format=webp","https://images.boatsgroup.com/resize/1/55/18/7295518_20191127110738010_1_XLARGE.jpg?w=1028&ratio=default&t=1758655515000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121535722-3.jpg?w=1028&ratio=default&t=1758655844000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121536280-4.jpg?w=1028&ratio=default&t=1758655918000&exact&format=webp","https://images.boatsgroup.com/resize/1/11/43/2005-mainship-34-pilot-sedan-rum-runner-ii-power-9941143-20250923121538657-1.jpg?w=1028&ratio=default&t=1758655866000&exact&format=webp"]', NULL, NULL, NULL, NULL, 'Oxnard, California, US', 'Oxnard', 'California', 'US', NULL, NULL, 'city', 'apple', 'failed', 'Oxnard, California, US', 'Apple Maps token exchange failed (401): {"error":{"message":"Not Authorized","details":[]}}', '2026-04-01T18:18:41.625Z', 1, 0);
