INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (10899, '10127358', 'YachtWorld', 'https://www.yachtworld.com/yacht/2003-formula-40-performance-cruiser-10127358/', 'Formula', '40 Performance Cruiser', 2003, '40ft', '119500', 'USD', 'San Diego, California', 'San Diego', 'California', 'US', '40'' Thunderbird Formula 40PC ''03 "Wine Down" The Formula 40 Performance cruiser is stylish, powerful and built with precision craftmanship. The expansive cockpit is beautifully arranged for entertaining with generous seating, excellent stowage and a seamless flow that invites guests to relax and socialize. Below decks she is exceptionally spacious, light and airy, an atmosphere rarely found in a performance cruiser of this size. Priced to sell!', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100737267-1.jpg?w=1920&h=267&t=1774459358000&exact=&format=webp","https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100737409-2.jpg?w=1920&ratio=default&t=1774459364000&exact=&format=webp","https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100737554-3.jpg?w=1920&ratio=default&t=1774459360000&exact=&format=webp","https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100737706-4.jpg?w=1920&ratio=default&t=1774459359000&exact=&format=webp","https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100738562-1.jpg?w=1920&ratio=default&t=1774459367000&exact=&format=webp","https://images.boatsgroup.com/resize/1/73/58/2003-thunderbird-formula-40pc-power-10127358-20260325100738691-2.jpg?w=1920&ratio=default&t=1774459363000&exact=&format=webp"]', 'Boat DetailsDescription40'' Thunderbird Formula 40PC ''03 "Wine Down" The Formula 40 Performance cruiser is stylish, powerful and built with precision craftmanship. The expansive cockpit is beautifully arranged for entertaining with generous seating, excellent stowage and a seamless flow that invites guests to relax and socialize. Below decks she is exceptionally spacious, light and airy, an atmosphere rarely found in a performance cruiser of this size. Priced to sell!Show MoreContact InformationPlease contact our office at (619) 224-2349Other DetailsDisclaimerThe Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.AccommodationsEnter from swim platform on port side into an extremely accommodating cockpit wit