INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (22543, '10008917', 'YachtWorld', 'https://www.yachtworld.com/yacht/2021-ranger-tugs-r-23-10008917/', 'Ranger', 'Tugs R-23', 2021, '23ft', '118900', 'USD', 'Brick Twp, New Jersey', 'Brick Twp', 'New Jersey', 'New Jersey', 'This 2021 Ranger Tugs R-23 is powered by a 200 HP Yamaha outboard. The first thing you will notice when looking at the R-23 is the dramatic, curved windshield and visor, which is emphasized by several overhead skylights. There is no shortage of light or visibility onboard the R-23, which incorporates four opening roof hatches, sliding side windows, and an opening glass bulkhead, providing a very open and airy feeling inside and out. Opening portlights also allow for a nice cross breeze in the cabin. The forward cabin on the R-23 has plenty of room for sitting around the teak table, separate sleeping for two or sleeping two together with the filler-cushion. The mid berth is great for kids or storage, and the dinette converts to a sleeper as the third berth. The well-appointed galley on the R-23 is standard with refrigerator/freezer, cooktop, and microwave. The forward head includes a marine toilet with holding tank, shower, sink, and mirror. Outfitted with the standard Garmin 942xsv GPS chartplotter with sonar, this model also includes the desirable optional xHD radar upgrade. VHF to stay in touch, illuminated compass, cabin night light, cockpit and exterior side trail lighting, and our patented built-in safety trailering lights (brake, turn, and reverse) are all standard equipment making the R-23 ready to cruise. The cockpit is built to fish and ready to entertain with standard rod holders, outlets, and folding bench seats. The R-23 is perfect for overnighting or extended cruises. It incorporates many of the same amenities as a larger cruising yacht that until now were not offered on a boat of her size and price point. Whether you are new to boating or a seasoned captain, the R-23 is the perfect boat for your next adventure. Yamaha 200HP (95 hrs) Aluminum tandem-axle tr…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/89/17/2021-ranger-tugs-r-23-power-10008917-20251112103204833-2.jpg?w=1920&h=267&t=1762973551000&exact=&format=webp","https://images.boatsgroup.com/resize/1/89/17/2021-ranger-tugs-r-23-power-10008917-20251112103053557-1.jpg?w=1920&ratio=default&t=1762973240000&exact=&format=webp","https://images.boatsgroup.com/resize/1/89/17/2021-ranger-tugs-r-23-power-10008917-20251112103039585-4.jpg?w=1920&ratio=default&t=1762973173000&exact=&format=webp","https://images.boatsgroup.com/resize/1/89/17/2021-ranger-tugs-r-23-power-10008917-20251112103043036-1.jpg?w=1920&ratio=default&t=1762973215000&exact=&format=webp","https://images.boatsgroup.com/resize/1/89/17/2021-ranger-tugs-r-23-power-100089