INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (9342, '10111360', 'YachtWorld', 'https://www.yachtworld.com/yacht/2000-ocean-yachts-70-super-sport-10111360/', 'Ocean', 'Yachts 70 Super Sport', 2000, '70ft', '749000', 'USD', 'Monmouth Beach, New Jersey', 'Monmouth Beach', 'New Jersey', 'US', 'Ready to go Fishing this Spring!! Major Upgrades and Installs over the Past Three Years! The Ocean 70 Super Sport was the largest and most luxurious model in the company’s history when she was introduced in 2000. She’s built on a very beamy modified-V hull with prop pockets (to reduce draft) and more transom deadrise (for a softer ride) than previous Ocean designs. The lavish four-stateroom floorplan of the 70 SS is arranged with the full-beam master stateroom aft, under the galley and dinette area, which is similar to the layouts found in most all of Ocean’s later models. A VIP stateroom is in the forepeak, and a utility room with a washer/dryer and freezer is located between the master stateroom and the second guest cabin. In a practical design touch, the flybridge is reached from either the cockpit or the salon. The cockpit, with over 150 square feet of space, comes with a full complement of fishing amenities and a custom mezzanine seating area with refrigerated compartments. Additional features include an enclosed flybridge, a bathtub in the master stateroom head, and three guest heads, each with a separate stall shower. An excellent performer, 1,400hp Cats cruise at 25 knots at 1,950 RPMs (32–33 knots top). Upgrades 2023-2024 New Garmin Electronics including 24", 16" & 7" Multifunction Displays New Garmin Radar - Fantom 6'' Open Array New Garmin Autopilot New Garmin AIS Starlink New Airmar Thru-hull Dual Channel CHIRP Transducer Custom Lewmar Windlass Installation and Polished Stainless Delta Anchor (As installed on current Vikings) 1,000 hour Caterpillar service performed within 150 hours ago New Exhaust Risers - Marine Exhaust Systems (Riviera Beach, FL) New Vetus Bowthruster Motor Recovered Stidd Helm and Companion Seats New High-Low High gloss salon table with s…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203589-58.jpg?w=400&h=267&t=1774649396000&exact&format=webp","https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203659-60.jpg?w=200&ratio=default&t=1774649405000&exact&format=webp","https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203668-61.jpg?w=200&ratio=default&t=1774649409000&exact&format=webp","https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203549-62.jpg?w=200&ratio=default&t=1774649394000&exact&format=webp","https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203262-59.jpg?w=200&ratio=default&t=1774649397000&exact&format=webp","https://images.boatsgroup.com/resize/1/13/60/2000-ocean-yachts-70-super-sport-power-10111360-20260317072203339-65.jpg?w=200&ratio=default&t=1774649394000&exact&format=webp"]', 'Boat DetailsDescription Ready to go Fishing this Spring!! Major Upgrades and Installs over the Past Three Years! The Ocean 70 Super Sport was the largest and most luxurious model in the company’s history when she was introduced in 2000. She’s built on a very beamy modified-V hull with prop pockets (to reduce draft) and more transom deadrise (for a softer ride) than previous Ocean designs. The lavish four-stateroom floorplan of the 70 SS is arranged with the full-beam master stateroom aft, under the galley and dinette area, which is similar to the layouts found in most all of Ocean’s later models. A VIP stateroom is in the forepeak, and a utility room with a washer/dryer and freezer is located between the master stateroom and the second guest cabin. In a practical design touch, the flybridge is reached from either the cockpit or the salon. The cockpit, with over 150 square feet of space, comes with a full complement of fishing amenities and a custom mezzanine seating area with refrigerated compartments. Additional features include an enclosed flybridge, a bathtub in the master stateroom head, and three guest heads, each with a separate stall shower. An excellent performer, 1,400hp Cats cruise at 25 knots at 1,950 RPMs (32–33 knots top). Upgrades 2023-2024 New Garmin Electronics including 24", 16" & 7" Multifunction Displays New Garmin Radar - Fantom 6'' Open Array New Garmin Autopilot New Garmin AIS Starlink New Airmar Thru-hull Dual Channel CHIRP Transducer Custom Lewmar Windlass Installation and Polished Stainless Delta Anchor (As installed on current Vikings) 1,000 hour Caterpillar service performed within 150 hours ago New Exhaust Ri