INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (12244, '10110980', 'YachtWorld', 'https://www.yachtworld.com/yacht/2020-regal-35-sport-coupe-10110980/', 'Regal', '35 Sport Coupe', 2020, '35ft', '269000', 'USD', 'New Bern, North Carolina', 'New Bern', 'North Carolina', 'US', '2020 Regal 35 Sport Couple Twin Volvo 300 HP W/ 165 on Starboard and Brand new less than 5 hours on the Port motor under warranty This 2020 Regal 35 Sport Coupe with twin Volvo Penta 300HP engines and joystick docking offers an exceptional blend of luxury, performance, and versatility. Featuring a spacious cockpit with retractable hardtop, flexible seating, and a beautifully appointed cabin with accommodations for four, this Regal is equally suited for entertaining or weekend cruising. Key Highlights Brand new factory Volvo Penta port engine – less than 5 hours (replaced under warranty) Twin Volvo Penta 300HP sterndrives Joystick docking system Retractable hardtop Air-conditioned cockpit Garmin Westerbeke generator Carpet and bow cushions included as well Extended swim platform Bow Cushions Brand New Isinglass Full set of new carpet for deck Cockpit The cockpit is designed for entertaining and relaxing, offering plenty of seating and premium amenities. Hardtop: Full-width sliding hardtop provides the flexibility of sun or shade depending on the conditions. Seating: Spacious conversational seating throughout the cockpit along with a comfortable double-wide helm seat. Sun Pad: The slide-away aft seat converts into a large sun pad at the touch of a button, opening up additional cockpit space when needed. Amenities: Wet bar with refrigerator and a removable cockpit table make entertaining easy. Climate Control: Air-conditioned cockpit for comfort during warmer days. Cabin & Interior Below deck, the Regal 35 Sport Coupe offers a bright and well-appointed interior with smart use of space. Salon: Large L-shaped sofa with a lifting seatback that converts into a queen-size berth. Forward Berth: Comfortable queen-size V-berth forward. Aft Cabin: Two facing sofas convert into an a…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155506201-1.jpg?w=1920&h=267&t=1773702610000&exact=&format=webp","https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155507384-2.jpg?w=1920&ratio=default&t=1773702610000&exact=&format=webp","https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155508541-3.jpg?w=1920&ratio=default&t=1773702611000&exact=&format=webp","https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155509549-4.jpg?w=1920&ratio=default&t=1773702613000&exact=&format=webp","https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155513674-1.jpg?w=1920&ratio=default&t=1773702617000&exact=&format=webp","https://images.boatsgroup.com/resize/1/9/80/2020-regal-35-sport-coupe-power-10110980-20260316155514754-2.jpg?w=1920&ratio=default&t=1773702618000&exact=&format=webp"]', 'Boat DetailsDescription2020 Regal 35 Sport Couple Twin Volvo 300 HP W/ 165 on Starboard and Brand new less than 5 hours on the Port motor under warranty This 2020 Regal 35 Sport Coupe with twin Volvo Penta 300HP engines and joystick docking offers an exceptional blend of luxury, performance, and versatility. Featuring a spacious cockpit with retractable hardtop, flexible seating, and a beautifully appointed cabin with accommodations for four, this Regal is equally suited for entertaining or weekend cruising. Key Highlights Brand new factory Volvo Penta port engine – less than 5 hours (replaced under warranty) Twin Volvo Penta 300HP sterndrives Joystick docking system Retractable hardtop Air-conditioned cockpit Garmin Westerbeke generator Carpet and bow cushions included as well Extended swim platform Bow Cushions Brand New Isinglass Full set of new carpet for deck Cockpit The cockpit is designed for entertaining and relaxing, offering plenty of seating and premium amenities. Hardtop: Full-width sliding hardtop provides the flexibility of sun or shade depending on the conditions. Seating: Spacious conversational seating throughout the cockpit along with a comfortable double-wide helm seat. Sun Pad: The slide-away aft seat converts into a large sun pad at the touch of a button, opening up additional cockpit space when needed. Amenities: Wet bar with refrigerator and a removable cockpit table make entertaining easy. Climate Control: Air-conditioned cockpit for comfort during warmer days. Cabin & Interior Below deck, the Regal 35 Sport Coupe offers a bright and well-appointed interior with smart use of space. Salon: Large L-shaped sofa with a lifting seatback that converts into a queen-size berth. F