INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (9755, '10106485', 'YachtWorld', 'https://www.yachtworld.com/yacht/2000-silverton-392-motor-yacht-10106485/', 'Silverton', '392 Motor Yacht', 2000, '43ft', '129000', 'USD', 'Southport, North Carolina', 'Southport', 'North Carolina', 'US', 'Super clean and low hour boat! Lovingly maintained and cared for with great eisenglass, no smells, this unique layout offers the same space as a Aft Cabin much larger. With the steps to access the bow on either side of the flybridge, this boat is even possible to run single handed. Very clean throughout and updated Garmin electronics on the bridge make this aft cabin a great weekend condo or an efficient cruiser perfect for the Great Loop! The Silverton 392 Motor Yacht, with its innovative “SideWalk” flybridge steps, offers much improvement in safety, space utilization, and mobility. Never before has going forward been so easy and so safe. High bulwarks, sturdy rails, and wide steps allow passengers to move easily all around the boat. The added benefit lies below in the gunnel to gunnel salon that rivals boats 10 feet longer. By opening up the salon, both full-width and full-length, owners can entertain, dine, or just relax in this truly spacious atmosphere. Fore and aft are equally sumptuous staterooms, and private heads with stall showers. Both staterooms even have standard innerspring mattresses for sleeping comfort.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123838847-0.jpg?w=1920&h=267&t=1773085264000&exact=&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123838729-1.jpg?w=1920&ratio=default&t=1773085250000&exact=&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908801-2.jpg?w=1920&ratio=default&t=1773085351000&exact=&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908827-3.jpg?w=1920&ratio=default&t=1773085352000&exact=&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908898-4.jpg?w=1920&ratio=default&t=1773085355000&exact=&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908834-5.jpg?w=1920&ratio=default&t=1773085353000&exact=&format=webp"]', 'Boat DetailsDescriptionSuper clean and low hour boat! Lovingly maintained and cared for with great eisenglass, no smells, this unique layout offers the same space as a Aft Cabin much larger. With the steps to access the bow on either side of the flybridge, this boat is even possible to run single handed. Very clean throughout and updated Garmin electronics on the bridge make this aft cabin a great weekend condo or an efficient cruiser perfect for the Great Loop! The Silverton 392 Motor Yacht, with its innovative “SideWalk” flybridge steps, offers much improvement in safety, space utilization, and mobility. Never before has going forward been so easy and so safe. High bulwarks, sturdy rails, and wide steps allow passengers to move easily all around the boat. The added benefit lies below in the gunnel to gunnel salon that rivals boats 10 feet longer. By opening up the salon, both full-width and full-length, owners can entertain, dine, or just relax in this truly spacious atmosphere. Fore and aft are equally sumptuous staterooms, and private heads with stall showers. Both staterooms even have standard innerspring mattresses for sleeping comfort.Show MoreContact InformationPlease contact Capt. Hatch Perry at 919-801-2136Other DetailsAdditional Units Included 2023 West Marine Products Dinghy DisclaimerThe Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.Need more details?Ask the sellerPropulsionEngine 1Engine Make:CaterpillarEngine Model:3116-350Engine Year:2000Tot…', '2026-04-01T17:59:55.351Z', '2026-04-01T17:59:55.351Z', NULL, NULL, NULL, NULL, 'Please contact Capt. Hatch Perry at 919-801-2136', 'Capt. Hatch Perry', '919-801-2136', 'Additional Units Included 2023 West Marine Products Dinghy DisclaimerThe Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', 'The Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', NULL, NULL, NULL, NULL, NULL, NULL, 'Engine 1Engine Make:CaterpillarEngine Model:3116-350Engine Year:2000Total Power:350hpEngine Hours:1500Engine Type:InboardDrive Type:Direct DriveFuel Type:DieselEngine 2Engine Make:CaterpillarEngine Model:3116-350Engine Year:2000Total Power:350hpEngine Hours:1500Engine Type:InboardFuel Type:Diesel', 'Caterpillar', '3116-350', '2000', '350hp', '1500', 'Inboard', 'Direct Drive', 'Diesel', NULL, NULL, 'DimensionsLength Overall:43.77ftMax Bridge Clearance:18.33ftMax Draft:3.25ftBeam:14.08ftWeightsDry Weight:23,577LbMiscellaneousDeadrise At Transom:17degHull Material:FiberglassHull Shape:Modified VeeKeel Type:OtherTanksFresh Water Tank:1 x 100 gal Fuel Tank:1 x 286 gal Holding Tank:1 x 60 gal', NULL, NULL, NULL, '43.77ft', '18.33ft', '3.25ft', NULL, '14.08ft', '23,577Lb', NULL, NULL, '17deg', 'Fiberglass', 'Modified Vee', 'Other', '1 x 100 gal', '1 x 286 gal', '1 x 60 gal', NULL, '["https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123838847-0.jpg?w=1028&ratio=default&t=1773085264000&exact&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123838729-1.jpg?w=1028&ratio=default&t=1773085250000&exact&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908801-2.jpg?w=1028&ratio=default&t=1773085351000&exact&format=webp","https://images.boatsgroup.com/resize/1/64/85/2000-silverton-392-motor-yacht-power-10106485-20260309123908827-3