INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (10487, '10124567', 'YachtWorld', 'https://www.yachtworld.com/yacht/2008-hatteras-64-motor-yacht-10124567/', 'Hatteras', '64 Motor Yacht', 2008, '64ft', '935000', 'USD', 'Wilmington, North Carolina', 'Wilmington', 'North Carolina', 'US', 'Preliminary Listing! Professional Photos and Video to come! Just minutes from the Wilmington International Airport, this 2008 64 Hatteras is easily accessible and ready to be seen! With a full detail and many recent upgrades, "Kroh''s Nest" is a tried and true example of a high-performance cruiser known for its exceptional build quality and spacious layout. The "Kroh''s Nest" features sleek, contemporary exterior styling matched to a luxurious interior finished to the industry''s highest standards. The 64 Motor Yacht incorporates Hatteras'' popular convex hull shape, allowing for more interior space forward and providing for a softer ride in rough water. Propeller tunnels afford this 116,700-pound motor yacht a 4''8" draft with the heaviest engines available, this boat is outfitted with C-32''s. The 64 features a full beam 190-square-foot salon and 146-square-foot galley, while providing an ample 10 inches of side decks for comfortable access to the bow sun lounge and anchor windlass. The spacious salon opens into the galley, dining and pilothouse, providing for an expansive living area. The full glass and stainless-steel salon door allows the aft deck to be an extension of the salon. Inside the salon, genuine black cherry wood veneers are finished in high-gloss to perfectly complement the yacht''s reveal-style cabinetry and decorative soffit overhead. The large salon windows offer an expansive view, while duets recessed into pockets provide privacy. Comfort and luxury abounds in the twin club chairs and custom-designed lounge with accessible storage beneath. The entertainment center features an updated smart 50" TV mounted forward and to port, making it visible from all parts of the salon. Situated between the twin club chairs is a convenient cabinet with plenty of bottle and…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180536502-2.jpg?w=1920&h=267&t=1774365425000&exact=&format=webp","https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180536105-1.jpg?w=1920&ratio=default&t=1774365425000&exact=&format=webp","https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180536826-3.jpg?w=1920&ratio=default&t=1774315241000&exact=&format=webp","https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180537202-4.jpg?w=1920&ratio=default&t=1774315239000&exact=&format=webp","https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180539682-1.jpg?w=1920&ratio=default&t=1774315241000&exact=&format=webp","https://images.boatsgroup.com/resize/1/45/67/2008-hatteras-64-motor-yacht-power-10124567-20260323180540079-2.jpg?w=1920&ratio=default&t=1774315242000&exact=&format=webp"]', 'Boat DetailsDescriptionPreliminary Listing! Professional Photos and Video to come! Just minutes from the Wilmington International Airport, this 2008 64 Hatteras is easily accessible and ready to be seen! With a full detail and many recent upgrades, "Kroh''s Nest" is a tried and true example of a high-performance cruiser known for its exceptional build quality and spacious layout. The "Kroh''s Nest" features sleek, contemporary exterior styling matched to a luxurious interior finished to the industry''s highest standards. The 64 Motor Yacht incorporates Hatteras'' popular convex hull shape, allowing for more interior space forward and providing for a softer ride in rough water. Propeller tunnels afford this 116,700-pound motor yacht a 4''8" draft with the heaviest engines available, this boat is outfitted with C-32''s. The 64 features a full beam 190-square-foot salon and 146-square-foot galley, while providing an ample 10 inches of side decks for comfortable access to the bow sun lounge and anchor windlass. The spacious salon opens into the galley, dining and pilothouse, providing for an expansive living area. The full glass and stainless-steel salon door allows the aft deck to be an extension of the salon. Inside the salon, genuine black cherry wood veneers are finished in high-gloss to perfectly complement the yacht''s reveal-style cabinetry and decorative soffit overhead. The large salon windows offer an expansive view, while duets recessed into pockets provide privacy. Comfort and luxury abounds in the twin club chairs and custom-designed lounge with accessible storage beneath. The entertainment center features an updated smart 50" TV mounted forward and to port, making it visible from all parts of the salon. Situated between the twin club chairs is a convenient cabinet wi…', '2026-04-01T18:17:36.038Z', '2026-04-01T18:17:36.038Z', NULL, NULL, NULL, NULL, 'Please contact Brian Horan at 910-679-4988', 'Brian Horan', '910-679-4988', 'Additional DescriptionA central stairwell accessible from the galley/pilothouse area leads to the lower deck. The full-beam master stateroom features 83 inches of headroom. Oval portlights to port and starboard provide an abundance of natural light as well as an emergency escape. Twin nightstands, dressers and wardrobes mirror each side of the king-size berth. The berth features cedar-lined storage accessed by gas-assisted cylinders. Dual hanging lockers add to the tremendous storage. For entertaining, custom cabinetry was crafted for the upgraded television. The master head features a walk-in shower, bowed cabinetry and Plexiglas mirror fascias above. A spacious port guest stateroom features side-by-side twins, while bow stateroom features a queen berth hinged with cedar-lined storage. Throughout the boat, air conditioning spills over the soffits running down the hull sides of each area, allowing the flow of air to spread over the entire length of the room. Air returns are routed through the cabinetry where possible to keep the headliner clean. All heads are equipped with an air-conditioning vent, full Plexiglas mirrors, bowed wood cabinets, solid-surface countertops and backsplas…', 'The Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', 'Electrical EquipmentShore Power Inlet:✓Generator:✓ElectronicsDepthsounder:✓Radar:✓TV Set:✓Navigation Center:✓Plotter:✓Autopilot:✓Radio:✓