INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (9835, '10129389', 'YachtWorld', 'https://www.yachtworld.com/yacht/1997-tarrab-77-motor-yacht-10129389/', 'Tarrab', '77 Motor Yacht', 1997, '77ft', '169000', 'USD', 'Baltimore, Maryland', 'Baltimore', 'Maryland', 'US', 'ALWAYS GO is a 1997 Tarrab 77'' Motor Yacht that is well built and looking for its new owner to complete her refit! ALL OFFERS CONSIDERED! Mechanically the engines fire right up and have had multiple extensive services including 1000-hour service, new hoses, after coolers & heat exchangers rebuilt, and rebuilt turbos. Bottom Paint had a complete refresh in 2024 along with prop speed. Interior the owner laid beautiful wood floors, the salon has new solid wood cabinetry, new solid surface counter tops, and new appliances. The boat needs headliner, lights, wall covering in the salon and galley as well as all staterooms. Forward and Starboard staterooms are original. Demo was completed for port side room converted to closet, Master stateroom was demoed and ready to lay new hardwoods which are matching of the salon and galley. Reach out for More Information! Features include: 4 staterooms, each w/ensuite head Separate crew''s quarters aft of engine room Day head on first level Large aft deck Full beam salon Oversize fly bridge w/grill, wet bar, lots of seating Full-beam engine room Chilled water air conditioning Awl grip paint Euro transom providing easy access to swim platform Engine / Mechanical Twin CATERPILLAR 3412C engines - 1300 horsepower each Two NORTHERN LIGHTS 30 KW Generators NAIAD stabilizers - Model 254 KEYPOWER bow thruster REVERSO Oil change unit for engines, generators, and marine gears', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184400777-4.jpg?w=1920&h=267&t=1774578187000&exact=&format=webp","https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184358548-1.jpg?w=1920&ratio=default&t=1774578187000&exact=&format=webp","https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184342695-3.jpg?w=1920&ratio=default&t=1774578187000&exact=&format=webp","https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184256212-1.jpg?w=1920&ratio=default&t=1774578187000&exact=&format=webp","https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184259188-4.jpg?w=1920&ratio=default&t=1774578187000&exact=&format=webp","https://images.boatsgroup.com/resize/1/93/89/1997-tarrab-77-motor-yacht-power-10129389-20260326184257408-2.jpg?w=1920&ratio=default&t=1774578187000&exact=&format=webp"]', 'Boat DetailsDescriptionALWAYS GO is a 1997 Tarrab 77'' Motor Yacht that is well built and looking for 