INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (21805, '9835509', 'YachtWorld', 'https://www.yachtworld.com/yacht/2017-prestige-500s-9835509/', 'Prestige', '500S', 2017, '50ft', '599000', 'USD', 'Baltimore, Maryland', 'Baltimore', 'Maryland', 'US', '$50,000 Price Reduction for Spring Sale!Experience luxury and performance with the 2017 Prestige Yachts 500 S, a stunning sport yacht designed for those who appreciate elegance and innovation. The Prestige 500 was Prestige''s top-selling model during the 2010''s, and her contemporary styling has kept the model fresh and stylish. This sleek and stylish vessel offers an exceptional blend of comfort, power, and modern amenities, making it perfect for cruising in style. Key Features: Volvo Penta IPS 600 Engines (600 Hours) – Effortless handling, fuel efficiency, and joystick docking for ultimate control. Spacious 3-Cabin Layout – Luxurious full-beam master suite with private entry, VIP stateroom, and guest cabin. Large Electric Sunroof & Aft Glass Doors – Seamlessly connect indoor and outdoor spaces for an open-air experience. Expansive Cockpit & Lounge Areas – Perfect for entertaining, featuring ample seating, a retractable sun awning, and an integrated grill. An integrated electric retractable cockpit awning is also equipped. Fully Equipped Galley – Modern appliances, ample storage, and a functional layout for onboard dining. State-of-the-Art Navigation & Electronics – Raymarine touchscreen displays, autopilot, radar, and premium sound system. Integrated Tender Garage -- Dinghy Included! This 2017 Prestige 500 S is an exceptional yacht, combining performance with the luxury and comfort of a much larger vessel. Whether for weekend getaways or extended cruising, this yacht delivers an unforgettable experience.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611122055604-1_XLARGE.jpg?w=1920&h=267&t=1749669681000&exact=&format=webp","https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611122253458-1_XLARGE.jpg?w=1920&ratio=default&t=1749669783000&exact=&format=webp","https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611122156385-1_XLARGE.jpg?w=1920&ratio=default&t=1749669784000&exact=&format=webp","https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611122152712-1_XLARGE.jpg?w=1920&ratio=default&t=1749669784000&exact=&format=webp","https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611121822342-1_XLARGE.jpg?w=1920&ratio=default&t=1749669784000&exact=&format=webp","https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-20250611121826045-1_XLARGE.jpg?w=1920&ratio=default&t=1749669784000&exact=&format=webp"]', 'Boat DetailsDescription$50,000 Price Reduction for Spring Sale!Experience luxury and performance with the 2017 Prestige Yachts 500 S, a stunning sport yacht designed for those who appreciate elegance and innovation. The Prestige 500 was Prestige''s top-selling model during the 2010''s, and her contemporary styling has kept the model fresh and stylish. This sleek and stylish vessel offers an exceptional blend of comfort, power, and modern amenities, making it perfect for cruising in style. Key Features: Volvo Penta IPS 600 Engines (600 Hours) – Effortless handling, fuel efficiency, and joystick docking for ultimate control. Spacious 3-Cabin Layout – Luxurious full-beam master suite with private entry, VIP stateroom, and guest cabin. Large Electric Sunroof & Aft Glass Doors – Seamlessly connect indoor and outdoor spaces for an open-air experience. Expansive Cockpit & Lounge Areas – Perfect for entertaining, featuring ample seating, a retractable sun awning, and an integrated grill. An integrated electric retractable cockpit awning is also equipped. Fully Equipped Galley – Modern appliances, ample storage, and a functional layout for onboard dining. State-of-the-Art Navigation & Electronics – Raymarine touchscreen displays, autopilot, radar, and premium sound system. Integrated Tender Garage -- Dinghy Included! This 2017 Prestige 500 S is an exceptional yacht, combining performance with the luxury and comfort of a much larger vessel. Whether for weekend getaways or extended cruising, this yacht delivers an unforgettable experience. Show MoreContact InformationPlease contact Ian Dimka at 410-693-7386FeaturesElectrical EquipmentShore Power Inlet:✓Generator:Onan 13.5kWElectronicsDepthsounder:✓Radar:RaymarineTV Set:Samsung Smart TV''sPlotter:RaymarineAutopilot:RaymarineRadio:Fusi…', '2026-04-01T17:49:19.483Z', '2026-04-01T17:49:19.483Z', NULL, NULL, NULL, NULL, 'Please contact Ian Dimka at 410-693-7386', 'Ian Dimka', '410-693-7386', NULL, NULL, 'Electrical EquipmentShore Power Inlet:✓Generator:Onan 13.5kWElectronicsDepthsounder:✓Radar:RaymarineTV Set:Samsung Smart TV''sPlotter:RaymarineAutopilot:RaymarineRadio:Fusion StereoCompass:✓GPS:RaymarineVHF:RaymarineFlat Screen TV:Samsung Smart TV''sInside EquipmentBow Thruster:✓Washing Machine:✓Electric Bilge Pump:✓Microwave Oven:CuisinartAir Conditioning:✓Electric Head:✓Hot Water:✓Refrigerator:✓Battery Charger:✓Outside EquipmentTeak Cockpit:✓Cockpit Shower:✓Cockpit Cushions:✓Cockpit Table:✓Swimming Ladder:✓Additional EquipmentUnderwater Lights:✓', 'Shore Power Inlet | Generator: Onan 13.5k | W', 'Depthsounder | Radar: Raymarine | TV Set: Samsung Smart TV''s | Plotter: Raymarine | Autopilot: Raymarine | Radio: Fusion Stereo | Compass | GPS: Raymarine | VHF: Raymarine | Flat Screen TV: Samsung Smart TV''s', 'Bow Thruster | Washing Machine | Electric Bilge Pump | Microwave Oven: Cuisinart | Air Conditioning | Electric Head | Hot Water | Refrigerator | Battery Charger', 'Teak Cockpit | Cockpit Shower | Cockpit Cushions | Cockpit Table | Swimming Ladder', 'Underwater Lights', 'Engine 1Engine Make:Volvo PentaEngine Model:IPS 600Total Power:435hpEngine Hours:600Engine Type:InboardDrive Type:Pod DriveFuel Type:DieselEngine 2Engine Make:Volvo PentaEngine Model:IPS 600Total Power:435hpEngine Hours:600Engine Type:InboardDrive Type:Pod DriveFuel Type:Diesel', 'Volvo Penta', 'IPS 600', NULL, '435hp', '600', 'Inboard', 'Pod Drive', 'Diesel', NULL, NULL, 'Speed & DistanceCruising Speed:25knMax Speed:30knRange:250nmDimensionsLength Overall:50ftMin Draft:3.33ftBeam:14.75ftWeightsDry Weight:29,750LbMiscellaneousDeadrise At Transom:17degHull Material:FiberglassTanksFresh Water Tank:2 x 84 gal Fuel Tank:2 x 172 gal Holding Tank:32 gal AccommodationsGuest Cabins:3Guest Heads:2', '25kn', '30kn', '250nm', '50ft', NULL, NULL, '3.33ft', '14.75ft', '29,750Lb', NULL, NULL, '17deg', 'Fiberglass', NULL, NULL, '2 x 84 gal', '2 x 172 gal', '32 gal', '2', '["https://images.boatsgroup.com/resize/1/55/9/2017-prestige-500-s-power-9835509-202506