INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (21803, '10071042', 'YachtWorld', 'https://www.yachtworld.com/yacht/2016-prestige-500s-10071042/', 'Prestige', '500S', 2016, '50ft', '579900', 'USD', 'Baltimore, Maryland', 'Baltimore', 'Maryland', 'US', '2016 Prestige 500 S A Refined Express Yacht with Intelligent Design and Turn-Key Readiness The 2016 Prestige 500 S rises above the ordinary express cruiser with a design that feels purposeful, elegant, and exceptionally livable. Her sleek, contemporary profile is matched by generous interior volume, smart sightlines, and a layout that prioritizes owner privacy without sacrificing guest comfort. From the private, mid-beam owner’s suite to the versatile indoor-outdoor entertaining spaces, this yacht was built for owners who value both style and substance—underway and at rest. Highlights & Equipment Twin Volvo Penta IPS 600s (786 hours) with joystick control Cockpit joystick docking station Oversized tender garage with electric launch system Electric sunroof over salon and helm Forward sunpad with cantilevering bimini Electric retractable cockpit sunshade Full Raymarine navigation suite (GPS, chartplotter, radar, autopilot, VHF) Bow thruster Washer/Dryer Icemaker Tropical air-conditioning package Exterior & Interior Living SpacesCockpit The cockpit is designed as the social hub of the yacht, offering an inviting blend of comfort and functionality. Ample seating surrounds a well-placed table, making it ideal for entertaining or relaxed dockside evenings. The electric retractable sunshade allows you to fine-tune sun and shade throughout the day, while easy access to the swim platform and tender garage enhances watersports and boarding convenience. A cockpit docking station provides excellent visibility and control when maneuvering in tight marinas. Salon & Helm Stepping inside, the salon immediately feels open and modern thanks to large windows and the electric sunroof overhead. Natural light floods the space, creating a bright, welcoming atmosphere. The helm is thoughtfully…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202054927233-3.jpg?w=1920&h=267&t=1770041069000&exact=&format=webp","https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202055214572-1.jpg?w=1920&ratio=default&t=1770041236000&exact=&format=webp","https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202055216349-4.jpg?w=1920&ratio=default&t=1770041238000&exact=&format=webp","https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202055215126-2.jpg?w=1920&ratio=default&t=1770041416000&exact=&format=webp","https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202055215723-3.jpg?w=1920&ratio=default&t=1770041238000&exact=&format=webp","https://images.boatsgroup.com/resize/1/10/42/2016-prestige-500s-power-10071042-20260202054930739-2.jpg?w=1920&ratio=default&t=1770041073000&exact=&format=webp"]', 'Boat DetailsDescription2016 Prestige 500 S A Refined Express Yacht with Intelligent Design and Turn-Key Readiness The 2016 Prestige 500 S rises above the ordinary express cruiser with a design that feels purposeful, elegant, and exceptionally livable. Her sleek, contemporary profile is matched by generous interior volume, smart sightlines, and a layout that prioritizes owner privacy without sacrificing guest comfort. From the private, mid-beam owner’s suite to the versatile indoor-outdoor entertaining spaces, this yacht was built for owners who value both style and substance—underway and at rest. Highlights & Equipment Twin Volvo Penta IPS 600s (786 hours) with joystick control Cockpit joystick docking station Oversized tender garage with electric launch system Electric sunroof over salon and helm Forward sunpad with cantilevering bimini Electric retractable cockpit sunshade Full Raymarine navigation suite (GPS, chartplotter, radar, autopilot, VHF) Bow thruster Washer/Dryer Icemaker Tropical air-conditioning package Exterior & Interior Living SpacesCockpit The cockpit is designed as the social hub of the yacht, offering an inviting blend of comfort and functionality. Ample seating surrounds a well-placed table, making it ideal for entertaining or relaxed dockside evenings. The electric retractable sunshade allows you to fine-tune sun and shade throughout the day, while easy access to the swim platform and tender garage enhances watersports and boarding convenience. A cockpit docking station provides excellent visibility and control when maneuvering in tight marinas. Salon & Helm Stepping inside, the salon immediately feels open and modern thanks to large windows and the electric sunroof overhead. Natural light floods the space, creating a bright, welcomi