INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (8289, '10131724', 'YachtWorld', 'https://www.yachtworld.com/yacht/2025-solace-37-cs-10131724/', 'Solace', '37 CS', 2025, '37ft', '799000', 'USD', 'Annapolis, Maryland', 'Annapolis', 'Maryland', 'US', '2025 SŌLACE 37 CS – 10 Hours • Triple Yamaha 350s • $750,000 – Annapolis, MD Turnkey, and Ready for Immediate Delivery This 2025 Solace 37 CS, offered directly by North Point Yacht Sales – an authorized Solace dealer, represents one of the most cutting-edge and versatile center consoles in the 37-foot class. This model is packed with features that set it and SŌLACE apart from the competition. Boasting a fuel capacity of over 500 gallons, this model ensures you reach your favorite fishing grounds or other destinations and return with ease, all while enjoying unparalleled comfort and style. Elevate your boating experience with the innovative and luxurious 37CS. Performance Engines: Triple Yamaha 350 V6 (1,050 hp total) Joystick Docking with Helm Master EX & Autopilot Cruise: ~33 knots • Top Speed: ~58 knots Range: Approx. 413 NM Standout Features Large cabin with A/C, head, sink, fridge/freezer, and overnight accommodations Integrated dive door, folding cockpit seats, bow lounging area Electric reel outlets, dual livewells (40 gal), large fish boxes Premium electronics, underwater lighting, upgraded JL Audio sound system Carbon fiber construction, built for strength, speed, and durability Full Solace factory warranties included Exceptional performance is a commitment we take seriously. Every SŌLACE boat undergoes rigorous quality control inspections throughout the building process with a final sea trial ensuring we have met our performance standards before delivering a boat to our customers. Available immediately for a private showing in Annapolis, MD. Contact North Point Yacht Sales to schedule your viewing or get additional images, detail videos, or spec confirmations.', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/76/49/2025-solace-37-cs-power-9777649-20250430132030133-1_XLARGE.jpg?w=400&h=267&t=1774792938000&exact&format=webp","https://images.boatsgroup.com/resize/1/76/49/2025-solace-37-cs-power-9777649-20250430132025017-1_XLARGE.jpg?w=200&ratio=default&t=1774792938000&exact&format=webp","https://images.boatsgroup.com/resize/1/76/49/2025-solace-37-cs-power-9777649-20250430131537710-1_XLARGE.jpg?w=200&ratio=default&t=1774792938000&exact&format=webp","https://images.boatsgroup.com/resize/1/76/49/2025-solace-37-cs-power-9777649-20250430131533541-1_XLARGE.jpg?w=200&ratio=default&t=1774792939000&exact&format=webp","https://images.boatsgroup.com/resize/1/32/19/2025-solace-37-cs-power-9513219-20240820101811201-1_XLARGE.jpg?w=200&ratio=default&t=1774792938000&exact&format=webp","https://images.boatsgroup.com/resize/1/3