INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (10101, '9906781', 'YachtWorld', 'https://www.yachtworld.com/yacht/2015-zodiac-pro-open-850-9906781/', 'Zodiac', 'Pro Open 850', 2015, '28ft', '129000', 'USD', 'Harwich, Massachusetts', 'Harwich', 'Massachusetts', 'US', 'Safe and stable for family fun AND Rugged and reliable as a work boat A unique blend of functionality and comfort, this Zodiac Pro sports twin low hour Yamaha 200HP engines tied into Helm-Master joystick, only one available on this model and Electronic Power Steering (EPS) for amazing maneuverability. A nice suite of Garmin Electronics and full head with storage throughoutcompletes this rugged Rigid Hull Inflatable. These boats have been used as tenders for America’s Cup vessels and functioned as durable transport for numerous expeditions. CUSTOM trailer included. Specifications • Length: 27'' 11"• Beam: 9'' 10"• Hull Weight: 2976 lbs• Motor Weight: 562 lbs each• Capacity: (20) Persons or 6173 lbs• Tube Diameter: 24"• Separate Air Chambers: (7)• Underdeck Fuel Tank with 140 Gallon Capacity• Fabric Type: CSM-Hypalon• Slide-On Tube System Factory Standard Hull / Tube Features • Deep V Fiberglass Hull• Self-Draining Molded Non-Skid Deck• Anchor Locker• Bow D-Ring• High Profile, Double Rubbing Strake• Removable Tubes for Easy Storage, Repair or Replacement Standard Features • Under Deck Wire Harness Routing• Navigation Lights• Foot Pump• Repair Kit• (2) Paddles• Optimum Step Down Into Hull Console• Command Center Bolster• Aft Bench Seat and Bow Cushion• Fuel / Water Separator• Transom Tie Downs• Battery Cut-Off Switch and Battery Box• Command Link Plus LCD Display Electronics • Garmin VHF• Fusion stereo with 4 speakers• Garmin 17 Inch Display with Garmin Radar• LED Lights GARMIN HD Radar Radome', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250826153507594-2.jpg?w=1920&h=267&t=1756248610000&exact=&format=webp","https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250811151152572-1.jpg?w=1920&ratio=default&t=1754951227000&exact=&format=webp","https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250826153506877-1.jpg?w=1920&ratio=default&t=1756248609000&exact=&format=webp","https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250811151249284-1.jpg?w=1920&ratio=default&t=1756247723000&exact=&format=webp","https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250811152015181-1.jpg?w=1920&ratio=default&t=1756247723000&exact=&format=webp","https://images.boatsgroup.com/resize/1/67/81/2015-zodiac-28-pro-optimum-power-9906781-20250811151534716-1.jpg?w=1920&ratio=default&t=1756247723000&exact=&format=webp"]', 'Boat Details