INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (22414, '9884407', 'YachtWorld', 'https://www.yachtworld.com/yacht/2011-grand-banks-46-eastbay-sx-9884407/', 'Grand', 'Banks 46 Eastbay SX', 2011, '50ft', '724999', 'USD', 'Danvers, Massachusetts', 'Danvers', 'Massachusetts', 'US', 'NEW ARRIVAL 2011 GRAND BANKS EASTBAY 46SX EQUIPPED W/ UPGRADED CUMMINS ZEUS DRIVES- 975 hours 1000 HOUR SERVICE JUST COMPLETED WITH RECORDS STARLINK INTERNET AND SIREN MARINE VESSEL MONITORING INSTALLED "Whole Life" is a meticulously cared for, prime example of the sought after Grand Banks Eastbay 46SX. While Spending most of her life in freshwater and indoor storage, "Whole Life" came to New England in 2021 where she has been pampered and upgraded annually. Always being stored indoors in the off-season since she has left the factory as well. This Eastbay has spent the last few years under current ownership with a full-time captain keeping all systems in check and cosmetics up to date to prevent any time off the water during the desired summer months in the Northeast. "Whole Life" also includes a hydraulic Freedom Lift as well as an AB 11 VST tender. Ideal for cruising, the Eastbay 46SX features a two stateroom, two head layout with a large galley down. Also equipped with a spare refrigerator as well as separate washer and dryer in the utility room. Ample storage and cedar closets make long distance cruises a breeze! Priced for immediate sale and ready for its next owners! The 46 Eastbay SX brings all the acclaimed performance, style and reliability of her predecessors - and then goes one great leap further, adding the revolutionary Zeus propulsion system from CMD. With joystick docking, pod-drive power and a range of intelligent innovations, this Eastbay is the definition of grace under power. The 46SX also offers a number of layout options, including both up- and down-galley configurations. A three-stateroom design is available, and owner have the option to add an additional crew cabin, too. Overall, the 46SX offers an unrivaled combination for the uncompromising buye…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103422061-2.jpg?w=1920&h=267&t=1774877839000&exact=&format=webp","https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103328654-3.jpg?w=1920&ratio=default&t=1774877839000&exact=&format=webp","https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103400186-2.jpg?w=1920&ratio=default&t=1774877839000&exact=&format=webp","https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103400823-3.jpg?w=1920&ratio=default&t=1774877839000&exact=&format=webp","https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103406917-1.jpg?w=1920&ratio=default&t=1774877839000&exact=&format=webp","https://images.boatsgroup.com/resize/1/44/7/2011-grand-banks-46-eastbay-sx-power-9884407-20250917103401371-4.jpg?w=1920&ratio=default&t=1774877839000&exact=&format=webp"]', 'Boat DetailsDescriptionNEW ARRIVAL 2011 GRAND BANKS EASTBAY 46SX EQUIPPED W/ UPGRADED CUMMINS ZEUS DRIVES- 975 hours 1000 HOUR SERVICE JUST COMPLETED WITH RECORDS STARLINK INTERNET AND SIREN MARINE VESSEL MONITORING INSTALLED "Whole Life" is a meticulously cared for, prime example of the sought after Grand Banks Eastbay 46SX. While Spending most of her life in freshwater and indoor storage, "Whole Life" came to New England in 2021 where she has been pampered and upgraded annually. Always being stored indoors in the off-season since she has left the factory as well. This Eastbay has spent the last few years under current ownership with a full-time captain keeping all systems in check and cosmetics up to date to prevent any time off the water during the desired summer months in the Northeast. "Whole Life" also includes a hydraulic Freedom Lift as well as an AB 11 VST tender. Ideal for cruising, the Eastbay 46SX features a two stateroom, two head layout with a large galley down. Also equipped with a spare refrigerator as well as separate washer and dryer in the utility room. Ample storage and cedar closets make long distance cruises a breeze! Priced for immediate sale and ready for its next owners! The 46 Eastbay SX brings all the acclaimed performance, style and reliability of her predecessors - and then goes one great leap further, adding the revolutionary Zeus propulsion system from CMD. With joystick docking, pod-drive power and a range of intelligent innovations, this Eastbay is the definition of grace under power. The 46SX also offers a number of layout options, including both up- and down-galley configurations. A three-stateroom design is available, and owner have the option to add an additional crew cabin, too. Overall, the 46SX offers an unrivaled combination for…', '2026-04-01T18:13:42.414Z', '2026-04-01T18:13:42.414Z', NULL, NULL, NULL, NULL, 'Please contact Connor Hurley at 978-774-8644', 'Connor Hurley', '978-774-8644', 'Additional InformationHull/Deck Dark blue gelcoat hull with gold cove stripe and white boot stripe Hydraulic Freedom tender lift Teak toe rail varnished high-gloss Two-tone non skid decks Self-draining anchor locker Air horn Teak trim on housetop Maxwell 1500 anchor windlass with foot controls on deck and controls at helm 45lb lewmar anchor Anchor washdown in anchor locker 50 amp shore power inlet on bow (optional) Stainless bow rail Teak flag staff varnished high-gloss Deck brush Boat hook Bucket Hose (4) fenders with covers (5) braided dock-lines Name boards mounted on pilothouse Cockpit Teak decking Transom door to swim platform Forward and aft-facing bench seats with storage underneath Cockpit speakers Manual bilge pump Dockside water hookup Cockpit shower Ice maker in starboard side cabinet Electrical Generator: Onan 11.5kw (upgraded from factory) 385 hours Glendenning shore power reel AC/DC electrical panels with volt and amp meters 2X 8D house batteries Dedicated engine/generator start batteries Battery charger Remote battery switches Emergency parallel Bilge pumpes Carbon monoxide detector Mechanical Cummins Zeus pods: QSC 600hp (upgraded) 975 HOURS Two full sets of spare p…', NULL, 'Electrical EquipmentShore Power Inlet:✓Generator:✓Inverter:✓ElectronicsDepthsounder:✓Radar:✓Log-Speedometer:✓Navigation Center:✓Plotter:✓DVD Player:✓Autopilot:✓Radio:✓Compass:✓CD Player:✓GPS:✓Cockpit Speakers:✓VHF:✓Flat Screen TV:✓Wi-Fi:✓AIS:✓Inside EquipmentWashing Machine:✓Electric Bilge Pump:✓Microwave Oven:✓Air Conditioning:✓Electric Head:✓Heating:✓Hot Water:✓Refrigerator:✓Battery Charger:✓Outside EquipmentTeak Cockpit:✓Tender:✓Cockpit Cushions:✓Swimming Ladder:✓', 'Shore Power Inlet | Generator | Inverter', 'D