INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (19738, '9370697', 'YachtWorld', 'https://www.yachtworld.com/yacht/2026-custom-ares-62-9370697/', 'Custom', 'Ares 62', 2026, '203ft', '45900000', 'EUR', 'Antalya, Turkey', 'Antalya', 'Turkey', 'US', 'The striking 203’ (62m) Ares superyacht SIMENA is a brand-new build and represents the pinnacle of modern yacht design, blended with traditional sailing elements. With close attention to detail and a commitment to excellence, Ares Shipyard has created a vessel that not only surpasses industry standards but sets a new benchmark for performance, comfort and style. From her sleek lines to her state-of-the-art systems, every aspect of SIMENA has been crafted for a discerning owner. At the heart of SIMENA''s design is a focus on performance luxury cruising. As a ketch, she combines the elegance of traditional sailing with the latest in cutting-edge technology to deliver a sailing experience like no other. With a cruising speed of 11 knots and a top speed of 14.5 knots, SIMENA offers transatlantic range even without utilizing her sails, making her the perfect vessel for exploring the world''s most remote destinations in comfort and style. Designed by the renowned naval architect Tanju Kalaycıoğlu of Taka Yacht Design, SIMENA''s exterior is sophisticated with clean lines and a striking profile that commands attention wherever she goes. “The inspiration behind the exterior lines was the clipper ships – especially the bow with fully rigged bowsprit and trail board,” explains Osman Tanju Kalaycioglu, naval architect and owner of Taka Yacht Design. Her composite (carbon and GRP) superstructure, believed to be the largest ever built for a yacht of her type, ensures both strength and agility, while her sleek hull glides effortlessly through the water, providing a smooth and stable ride in all conditions. Step inside, and you''ll discover an interior that pays homage to the classic inspiration seen on her exterior. SIMENA''s interior, designed by the award-winning studio Design Unlimited,…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023053317-1.jpg?w=1920&h=267&t=1774000136000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023055736-2.jpg?w=1920&ratio=default&t=1773999961000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023057668-3.jpg?w=1920&ratio=default&t=1773999965000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023059863-4.jpg?w=1920&ratio=default&t=1773999967000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023107135-1.jpg?w=1920&ratio=default&t=1773999970000&exact=&format=webp","https://images.boatsgroup.com/resize/1/6/97/2026-custom-ares-62-sail-9370697-20260320023109242-2.jpg?w=1920&ratio=default&t=1773999972000&exact=&format=webp"]', 'Boat DetailsDescriptionThe striking 203’ (62m) Ares superyacht SIMENA is a brand-new build and represents the pinnacle of modern yacht design, blended with traditional sailing elements. With close attention to detail and a commitment to excellence, Ares Shipyard has created a vessel that not only surpasses industry standards but sets a new benchmark for performance, comfort and style. From her sleek lines to her state-of-the-art systems, every aspect of SIMENA has been crafted for a discerning owner. At the heart of SIMENA''s design is a focus on performance luxury cruising. As a ketch, she combines the elegance of traditional sailing with the latest in cutting-edge technology to deliver a sailing experience like no other. With a cruising speed of 11 knots and a top speed of 14.5 knots, SIMENA offers transatlantic range even without utilizing her sails, making her the perfect vessel for exploring the world''s most remote destinations in comfort and style. Designed by the renowned naval architect Tanju Kalaycıoğlu of Taka Yacht Design, SIMENA''s exterior is sophisticated with clean lines and a striking profile that commands attention wherever she goes. “The inspiration behind the exterior lines was the clipper ships – especially the bow with fully rigged bowsprit and trail board,” explains Osman Tanju Kalaycioglu, naval architect and owner of Taka Yacht Design. Her composite (carbon and GRP) superstructure, believed to be the largest ever built for a yacht of her type, ensures both strength and agility, while her sleek hull glides effortlessly through the water, providing a smooth and stable ride in all conditions. Step inside, and you''ll discover an interior that pays homage to the classic inspiration seen on her exterior. SIMENA''s interior, designed by the award-winning s…', '2026-04-01T03:43:09.578Z', '2026-04-01T03:43:09.578Z', NULL, NULL, NULL, NULL, 'Please contact Sean McCarter at +34 679 897 108', 'Sean McCarter', NULL, 'DESCRIPTION OF THE YACHTSimena is a luxury, performance cruising ketch, designed by Taka Yachts with classic lines and fitted with state-of-the-art parallel hybrid technology offering a clean, classic feel to a contemporary interior by Design Unlimited. A yacht capable of cruising the world''s oceans in utmost comfort, safety, and style. Built with a marine-grade steel hull and the largest composite (carbon and GRP) superstructure of a yacht of this type to date. Aluminum masts with stainless rod rigging by acclaimed naval engineer Chris Mitchell. The Parallel Hybrid propulsion system allows for six different modes of diesel, electric, combined, and regeneration. When delivered, at 62m LOA, SIMENA will join a fleet of 12 Sailing Yachts over 60m size range under 500GT. SIMENA - Highlights at a glance Rina Charter Unrestricted Navigation RIG Certification Cayman Islands Registry High Strength Steel (AH36) Hull and Carbon epoxy foam Superstructure. Certified Crane with 2000 SWL located on foredeck. Custom carbon-composite 7,5m limo tender with Yanmar diesel engine. Custom RIB with Yanmar diesel engine. CCTV System consists of 36 cameras including night vision. Ethically sourced real My…', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engine Make:MANEngine Model:D2862LE438Engine Year:2026Total Power:1182.78hpEngine Type:InboardFuel Type:Diesel', 'MAN', 'D2862LE438', '2026', '1182.78hp', NULL, 'Inboard', NULL, 'Diesel', NULL, NULL, 'Speed & DistanceCruising Speed:5.94knMax Speed:7.56knRange:3239.74nmDimensionsLength Overall:203.41ftMax Draft:15.49ftMin Draft:15.49ftBeam:35.43ftWeightsGross Tonnage:498tMiscellaneousHull Material:SteelTanksFresh Water Tank:3698.41 gal Fuel Tank:12046.25 gal Holding Tank:418.71 gal AccommodationsGuest Cabins:6Guest Heads:6Crew Cabins:4Crew Heads:4', '5.94kn', '7.56kn', '3239.74n