INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (15889, '10034415', 'YachtWorld', 'https://www.yachtworld.com/yacht/2016-alia-yachts-alia-yachts-60m-10034415/', 'Alia', 'Yachts Alia Yachts 60M', 2016, '197ft', '39500000', 'EUR', 'West Palm Beach, Florida', 'West Palm Beach', 'Florida', 'US', 'SUN DECK Beginning up top, Samurai’s vast sun deck features an elevated Jacuzzi from which guests can take in the panoramic views and water-jet massage. Large sunpads here offer lots of space for sunbathing, while a protected lounging area nearby offers respite from the sun. Guests are shielded from the wind by glass paneling that surrounds the deck and offers unobstructed views of the water. WHEELHOUSE DECK This spacious level of the yacht is reserved for outdoor dining on the aft deck, or indoor relaxation in the salon. An oversized outdoor table is ideal for meals prepared by the yacht chef or Sunday morning brunch served by the crew. Aft of the table is an outdoor living space edged with white sofa seating and centered by two large low tables. Moving indoors, the salon offers various conversation areas with sofas and loose armchairs, and is an excellent option for movie nights or social gatherings. All the way forward, a Portuguese bridge leads to a quiet spot laden with sunpads and optional shading to take in the views. MAIN DECK The main deck aft features an intimate seating area outdoors, ideal for a late-night cocktail. Once inside, a vast, full-beam main salon with Asian-inspired décor welcomes guests to a plush lounging space with plenty of seating and floor-to-ceiling windows that bring in the outdoors. Just forward, a formal dining space seats up to ten guests and boasts two recessed ceiling panels that are well lit and edged in black lacquer. Moving forward on this deck, guest accommodations each feature a private en suite. The master suite is located all the way forward, and features a private lounging area, as well as an oversized dressing area. ACCOMMODATION DECK A true indoor/outdoor haven, this deck is host to a large beach club edged by a fold-down sw…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/47/13/9304713_20240319143327758_1_XLARGE.jpg?w=400&h=267&t=1765380404000&exact&format=webp","https://images.boatsgroup.com/resize/1/47/13/9304713_20240320071810567_1_XLARGE.jpg?w=200&ratio=default&t=1765380403000&exact&format=webp","https://images.boatsgroup.com/resize/1/47/13/9304713_20240320071905801_1_XLARGE.jpg?w=200&ratio=default&t=1765380404000&exact&format=webp","https://images.boatsgroup.com/resize/1/47/13/9304713_20240320071937267_1_XLARGE.jpg?w=200&ratio=default&t=1765380403000&exact&format=webp","https://images.boatsgroup.com/resize/1/47/13/9304713_20240320072029943_1_XLARGE.jpg?w=200&ratio=default&t=1765380404000&exact&format=webp","https://imag