INSERT OR REPLACE INTO boats (id, listing_id, source, url, make, model, year, length, price, currency, location, city, state, country, description, seller_type, listing_type, images, full_text, scraped_at, updated_at, search_length_min, search_length_max, search_type, search_location, contact_info, contact_name, contact_phone, other_details, disclaimer, features, electrical_equipment, electronics, inside_equipment, outside_equipment, additional_equipment, propulsion, engine_make, engine_model, engine_year_detail, total_power, engine_hours, engine_type_detail, drive_type, fuel_type_detail, propeller_type, propeller_material, specifications, cruising_speed, max_speed, range, length_overall, max_bridge_clearance, max_draft, min_draft_detail, beam_detail, dry_weight, windlass, electrical_circuit, deadrise_at_transom, hull_material, hull_shape, keel_type, fresh_water_tank, fuel_tank, holding_tank, guest_heads, source_images, entity_id, superseded_by_boat_id, dedupe_method, dedupe_confidence, normalized_location, normalized_city, normalized_state, normalized_country, geo_lat, geo_lng, geo_precision, geo_provider, geo_status, geo_query, geo_error, geo_updated_at, geo_normalization_version, needs_rescrape) VALUES (15891, '9592506', 'YachtWorld', 'https://www.yachtworld.com/yacht/2004-amels-171-9592506/', 'Amels', '171', 2004, '171ft', '19950000', 'EUR', 'West Palm Beach, Florida', 'West Palm Beach', 'Florida', 'US', 'The elegant 52m (170.6ft) NITA K II is a Dutch pedigree superyacht launched by Amels in 2004. This stunning vessel features meticulously crafted interiors by Alberto Pinto and Laura Sessa, paired with an exterior design by the renowned Terence Disdale. Constructed with a steel hull and aluminum superstructure, NITA K II boasts an impressive volume of 628GT. Since her debut, she has proven to be a versatile yacht, appealing to seasoned yachtsmen for both private use and a successful charter program. NITA K II presents in turn-key condition, having been meticulously maintained by her experienced crew and undergoing numerous refits most recently in 2024. NITA K II comfortably accommodates up to 12 guests in five luxurious cabins. The full-beam master cabin on the main deck features his-and-hers en suites, walk-in wardrobes, and an adjoining office offering a private work space. On the lower deck, four spacious guest cabins with king beds can be found including two VIP suites equipped with jet tubs and oversized showers, along with two pullman bunks. Her main deck lounge and sky lounge are comfortable spaces flooded with natural light from her large windows on either side. In addition to her stunning interior, NITA K II offers generous exterior deck spaces, including a large sun deck with a jacuzzi and sun pads, a fully equipped bar under a hardtop, and an expansive sun lounge at the rear. The upper deck aft features open-air dining and lounging, while the main deck aft includes a spacious lounge area. The exterior layout is perfect for guest entertainment and relaxation, allowing everyone on board to enjoy their time together. Powered by twin 1,200hp Cummins diesel engines, NITA K II cruises comfortably at 12.5 knots and can reach a maximum speed of 15 knots. With a transa…', 'dealer', 'sale', '["https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063722991-1_XLARGE.jpg?w=400&h=267&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063721976-1_XLARGE.jpg?w=200&ratio=default&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063720975-1_XLARGE.jpg?w=200&ratio=default&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063725000-1_XLARGE.jpg?w=200&ratio=default&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063726001-1_XLARGE.jpg?w=200&ratio=default&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063727111-1_XLARGE.jpg?w=200&ratio=default&t=1729777195000&exact&format=webp"]', 'Boat DetailsDescriptionThe elegant 52m (170.6ft) NITA K II is a Dutch pedigree superyacht launched by Amels in 2004. This stunning vessel features meticulously crafted interiors by Alberto Pinto and Laura Sessa, paired with an exterior design by the renowned Terence Disdale. Constructed with a steel hull and aluminum superstructure, NITA K II boasts an impressive volume of 628GT. Since her debut, she has proven to be a versatile yacht, appealing to seasoned yachtsmen for both private use and a successful charter program. NITA K II presents in turn-key condition, having been meticulously maintained by her experienced crew and undergoing numerous refits most recently in 2024. NITA K II comfortably accommodates up to 12 guests in five luxurious cabins. The full-beam master cabin on the main deck features his-and-hers en suites, walk-in wardrobes, and an adjoining office offering a private work space. On the lower deck, four spacious guest cabins with king beds can be found including two VIP suites equipped with jet tubs and oversized showers, along with two pullman bunks. Her main deck lounge and sky lounge are comfortable spaces flooded with natural light from her large windows on either side. In addition to her stunning interior, NITA K II offers generous exterior deck spaces, including a large sun deck with a jacuzzi and sun pads, a fully equipped bar under a hardtop, and an expansive sun lounge at the rear. The upper deck aft features open-air dining and lounging, while the main deck aft includes a spacious lounge area. The exterior layout is perfect for guest entertainment and relaxation, allowing everyone on board to enjoy their time together. Powered by twin 1,200hp Cummins diesel engines, NITA K II cruises comfortably at 12.5 knots and can reach a maximum speed of…', '2026-03-31T14:09:59.111Z', '2026-03-31T14:09:59.111Z', NULL, NULL, NULL, NULL, 'Please contact Crispin Baynes at +1 (646) 241 8446', 'Crispin Baynes', '+1 (646) 241 8446', 'DisclaimerThe Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', 'The Company offers the details of this vessel in good faith but cannot guarantee or warrant the accuracy of this information nor warrant the condition of the vessel. A buyer should instruct his agents, or his surveyors, to investigate such details as the buyer desires validated. This vessel is offered subject to prior sale, price change, or withdrawal without notice.', NULL, NULL, NULL, NULL, NULL, NULL, 'Engine 1Engine Make:CumminsEngine Model:KT 38-M2Total Power:1200hpEngine Type:InboardFuel Type:DieselEngine 2Engine Make:CumminsEngine Model:KT 38-M2Total Power:1200hpEngine Type:InboardFuel Type:Diesel', 'Cummins', 'KT 38-M2', NULL, '1200hp', NULL, 'Inboard', NULL, 'Diesel', NULL, NULL, 'Speed & DistanceCruising Speed:12.5knMax Speed:15knRange:5000nmDimensionsLength Overall:170.6ftMax Draft:10.17ftBeam:29.53ftWeightsGross Tonnage:628tMiscellaneousHull Material:SteelTanksFresh Water Tank:4754.31 gal Fuel Tank:31172.32 gal Holding Tank:AccommodationsGuest Cabins:5Crew Cabins:7', '12.5kn', '15kn', '5000nm', '170.6ft', NULL, '10.17ft', NULL, '29.53ft', NULL, NULL, NULL, NULL, 'Steel', NULL, NULL, '4754.31 gal', '31172.32 gal', NULL, NULL, '["https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-power-9592506-20241024063722991-1_XLARGE.jpg?w=1028&ratio=default&t=1729777195000&exact&format=webp","https://images.boatsgroup.com/resize/1/25/6/2004-amels-amels-171-p